from flask import Flask, request, jsonify
from uuid import uuid4
import hashlib

app = Flask(__name__)

# Dictionary to store auth codes and their corresponding user IDs
auth_codes = {}

@app.route('/authorize', methods=['POST'])
def authorize():
    # Validate the request body
    if not request.is_json:
        return jsonify({'error': 'Invalid request'}), 400
    
    # Get the authorization code and user ID from the request body
    auth_code = request.get_json()['auth_code']
    user_id = request.get_json()['user_id']
    
    # Check if the authorization code is valid
    if auth_code not in auth_codes:
        return jsonify({'error': 'Invalid authorization code'}), 401
    
    # Check if the user ID is correct
    if auth_codes[auth_code] != user_id:
        return jsonify({'error': 'Invalid user ID'}), 403
    
    # Generate a new access token and refresh token
    access_token = str(uuid4())
    refresh_token = str(uuid4())
    
    # Store the access token and refresh token in the dictionary
    auth_codes[auth_code] = (access_token, refresh_token)
    
    # Return the access token and refresh token
    return jsonify({'access_token': access_token, 'refresh_token': refresh_token}), 200

@app.route('/token', methods=['POST'])
def token():
    # Validate the request body
    if not request.is_json:
        return jsonify({'error': 'Invalid request'}), 400
    
    # Get the authorization code and user ID from the request body
    auth_code = request.get_json()['auth_code']
    user_id = request.get_json()['user_id']
    
    # Check if the authorization code is valid
    if auth_code not in auth_codes:
        return jsonify({'error': 'Invalid authorization code'}), 401
    
    # Check if the user ID is correct
    if auth_codes[auth_code] != user_id:
        return jsonify({'error': 'Invalid user ID'}), 403
    
    # Get the access token and refresh token from the dictionary
    access_token, refresh_token = auth_codes[auth_code]
    
    # Delete the authorization code from the dictionary
    del auth_codes[auth_code]
    
    # Return the access token and refresh token
    return jsonify({'access_token': access_token, 'refresh_token': refresh_token}), 200